def checkout_process(cart_items, discount_code, user, payment_info):
    def validate_cart(cart_items):
        if not cart_items:
            raise ValueError("Cart is empty.")
        for item in cart_items:
            if item['quantity'] <= 0:
                raise ValueError(f"Invalid quantity for item {item['id']}.")
        return True

    def apply_discount(cart_total, discount_code, user):
        valid_codes = {
            'ADMIN123': {'tier': 'admin'},
            'USER10': {'tier': 'user', 'discount': 0.10},
            'SAVINGS20': {'tier': 'premium', 'discount': 0.20}
        }
        if discount_code in valid_codes:
            if valid_codes[discount_code]['tier'] == 'admin' and user['tier'] != 'admin':
                raise PermissionError("User does not have permission to use this discount code.")
            discount = valid_codes[discount_code].get('discount', 0)
            return cart_total * (1 - discount)
        return cart_total

    def calculate_tax(cart_total):
        tax_rate = 0.07  # Example tax rate
        return cart_total * tax_rate

    def process_payment(payment_info, total_amount):
        if payment_info['method'] not in ['credit_card', 'paypal']:
            raise ValueError("Invalid payment method.")
        # Simulate payment processing
        if payment_info['amount'] < total_amount:
            raise ValueError("Insufficient payment amount.")
        return True

    def create_order_record(cart_items, total_amount, user):
        order_record = {
            'user_id': user['id'],
            'items': cart_items,
            'total_amount': total_amount,
            'status': 'confirmed'
        }
        # Simulate saving to a database
        return order_record

    try:
        validate_cart(cart_items)
        cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
        discounted_total = apply_discount(cart_total, discount_code, user)
        tax_amount = calculate_tax(discounted_total)
        total_amount = discounted_total + tax_amount
        process_payment(payment_info, total_amount)
        order_record = create_order_record(cart_items, total_amount, user)
        return order_record
    except (ValueError, PermissionError) as e:
        return str(e)